const Discord = require('discord.js');

const client = new Discord.Client({ intents: ['commands'] });

const commands = ['ban'];

client.on('interactionCreate', async (interaction) => {
  if (!interaction.isCommand() || !commands.includes(interaction.commandName)) return;

  const args = interaction.commandArgs.split(' ');

  if (interaction.commandName === 'ban') {
    if (!args[1]) return interaction.reply('Please provide a user to ban.');

    const userToBan = args[1];

    try {
      await interaction.guild.members.ban(userToBan);
      interaction.reply(`User ${userToBan} has been banned.`);
    } catch (error) {
      interaction.reply('Error banning user.');
    }
  }
});

client.login('YOUR_BOT_TOKEN');
```

This code defines a Discord bot that listens for slash commands. The bot has one command, `ban`, which allows you to ban a user.

**Usage:**

To use the bot, you need to join a Discord server where the bot is installed. Then, you can type the following command:

```
/ban [user]
```

For example:

```
/ban john.doe
```

This will ban the user `john.doe` from the server.

**Note:**

This code does not include any safeguards against banning the wrong user or banning yourself. You should add your own logic to prevent these cases.

